import { RouteProp, useNavigation, useRoute } from '@react-navigation/native';
import { NativeStackNavigationProp } from '@react-navigation/native-stack';
import React, { useEffect, useState } from 'react';
import { ActivityIndicator, Pressable, SafeAreaView, StyleSheet, Text, View } from 'react-native';
import { formatCurrency, formatOrderNumber } from '../data/orderModule';
import { RootStackParamList } from '../navigation/AppNavigator';
import { getOrderById, OrderRecord } from '../services/firebaseService';

type RouteProps = RouteProp<RootStackParamList, 'OrderConfirmed'>;
type NavigationProp = NativeStackNavigationProp<RootStackParamList>;

const OrderConfirmedScreen = () => {
  const route = useRoute<RouteProps>();
  const navigation = useNavigation<NavigationProp>();
  const [order, setOrder] = useState<OrderRecord | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let active = true;

    const loadOrder = async () => {
      const data = await getOrderById(route.params.orderId);
      if (active) {
        setOrder(data);
        setLoading(false);
      }
    };

    loadOrder();
    return () => {
      active = false;
    };
  }, [route.params.orderId]);

  if (loading) {
    return (
      <SafeAreaView style={styles.loaderContainer}>
        <ActivityIndicator size="large" color="#1E7A45" />
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.pageGlow} />
      <View style={styles.ticket}>
        <View style={styles.topPanel}>
          <View style={styles.badge}>
            <Text style={styles.badgeText}>Order placed</Text>
          </View>
          <View style={styles.checkCircle}>
            <Text style={styles.checkMark}>OK</Text>
          </View>
          <Text style={styles.title}>Your water can order is confirmed</Text>
          <Text style={styles.subtitle}>
            The booking has been accepted and the delivery team can now prepare your cans.
          </Text>
        </View>

        <View style={styles.perforationRow}>
          <View style={styles.cutout} />
          <View style={styles.dashedLine} />
          <View style={styles.cutout} />
        </View>

        <View style={styles.detailsPanel}>
          <View style={styles.priceHero}>
            <Text style={styles.priceHeroLabel}>Final amount</Text>
            <Text style={styles.priceHeroValue}>{formatCurrency(order?.totalAmount ?? 0)}</Text>
            <Text style={styles.priceHeroSubtext}>
              {order?.paymentMethod || 'Cash on Delivery'} • {order?.quantity ?? 0} cans
            </Text>
          </View>

          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Order number</Text>
            <Text style={styles.detailValue}>{formatOrderNumber(order)}</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Delivery window</Text>
            <Text style={styles.detailValue}>{order?.expectedDeliveryTime || 'Today, 30-45 min'}</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Delivery address</Text>
            <Text style={styles.detailValue}>{order?.address || 'Saved customer address'}</Text>
          </View>
          <View style={styles.detailRow}>
            <Text style={styles.detailLabel}>Payment status</Text>
            <Text style={styles.detailValue}>{order?.paymentStatus === 'paid' ? 'Paid successfully' : 'Pay on delivery'}</Text>
          </View>

          <View style={styles.greenNote}>
            <Text style={styles.greenNoteTitle}>What happens next</Text>
            <Text style={styles.greenNoteText}>1. The shop prepares your cans.</Text>
            <Text style={styles.greenNoteText}>2. Delivery status updates appear in tracking.</Text>
            <Text style={styles.greenNoteText}>3. You receive the order in your selected time window.</Text>
          </View>
        </View>

        <Pressable style={styles.primaryButton} onPress={() => navigation.navigate('OrderTracking', { orderId: order?.id })}>
          <Text style={styles.primaryButtonText}>Track Order</Text>
        </Pressable>
        <Pressable style={styles.secondaryButton} onPress={() => navigation.navigate('NewOrder', { reorder: true })}>
          <Text style={styles.secondaryButtonText}>Order Again</Text>
        </Pressable>
        <Pressable style={styles.textButton} onPress={() => navigation.navigate('CustomerHome')}>
          <Text style={styles.textButtonText}>Back to dashboard</Text>
        </Pressable>
      </View>
    </SafeAreaView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#EAF7EE',
    justifyContent: 'center',
    padding: 18
  },
  loaderContainer: {
    flex: 1,
    alignItems: 'center',
    justifyContent: 'center',
    backgroundColor: '#EAF7EE'
  },
  pageGlow: {
    position: 'absolute',
    top: -60,
    right: -30,
    width: 220,
    height: 220,
    borderRadius: 110,
    backgroundColor: '#D6F0DE'
  },
  ticket: {
    backgroundColor: '#FFFFFF',
    borderRadius: 34,
    overflow: 'hidden'
  },
  topPanel: {
    backgroundColor: '#1E7A45',
    paddingHorizontal: 24,
    paddingTop: 24,
    paddingBottom: 28,
    alignItems: 'center'
  },
  badge: {
    backgroundColor: 'rgba(255,255,255,0.18)',
    borderRadius: 999,
    paddingHorizontal: 12,
    paddingVertical: 7
  },
  badgeText: {
    color: '#F2FFF5',
    fontSize: 12,
    fontWeight: '800',
    textTransform: 'uppercase'
  },
  checkCircle: {
    marginTop: 18,
    width: 84,
    height: 84,
    borderRadius: 42,
    backgroundColor: '#F4FFF7',
    alignItems: 'center',
    justifyContent: 'center'
  },
  checkMark: {
    color: '#1E7A45',
    fontSize: 22,
    fontWeight: '900'
  },
  title: {
    marginTop: 18,
    color: '#FFFFFF',
    fontSize: 28,
    fontWeight: '900',
    textAlign: 'center',
    lineHeight: 35
  },
  subtitle: {
    marginTop: 10,
    color: '#D8F3E1',
    fontSize: 14,
    lineHeight: 22,
    textAlign: 'center'
  },
  perforationRow: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#FFFFFF'
  },
  cutout: {
    width: 26,
    height: 26,
    borderRadius: 13,
    backgroundColor: '#EAF7EE',
    marginHorizontal: -13
  },
  dashedLine: {
    flex: 1,
    borderTopWidth: 2,
    borderStyle: 'dashed',
    borderColor: '#D9EADB'
  },
  detailsPanel: {
    paddingHorizontal: 22,
    paddingTop: 18,
    paddingBottom: 10
  },
  priceHero: {
    backgroundColor: '#F4FBF6',
    borderRadius: 24,
    padding: 18,
    marginBottom: 18
  },
  priceHeroLabel: {
    color: '#5C7C69',
    fontSize: 12,
    fontWeight: '800',
    textTransform: 'uppercase'
  },
  priceHeroValue: {
    marginTop: 8,
    color: '#173726',
    fontSize: 30,
    fontWeight: '900'
  },
  priceHeroSubtext: {
    marginTop: 6,
    color: '#5C7C69',
    fontSize: 13,
    lineHeight: 20
  },
  detailRow: {
    paddingVertical: 12,
    borderBottomWidth: 1,
    borderBottomColor: '#EDF4EF'
  },
  detailLabel: {
    color: '#6E8678',
    fontSize: 12,
    fontWeight: '800',
    textTransform: 'uppercase'
  },
  detailValue: {
    marginTop: 6,
    color: '#173726',
    fontSize: 16,
    fontWeight: '800',
    lineHeight: 23
  },
  greenNote: {
    marginTop: 18,
    borderRadius: 22,
    backgroundColor: '#E7F7EA',
    padding: 16
  },
  greenNoteTitle: {
    color: '#1E7A45',
    fontSize: 15,
    fontWeight: '900'
  },
  greenNoteText: {
    marginTop: 8,
    color: '#2E6644',
    fontSize: 13,
    lineHeight: 19
  },
  primaryButton: {
    marginTop: 6,
    marginHorizontal: 22,
    backgroundColor: '#1E7A45',
    borderRadius: 20,
    paddingVertical: 16,
    alignItems: 'center'
  },
  primaryButtonText: {
    color: '#FFFFFF',
    fontSize: 17,
    fontWeight: '900'
  },
  secondaryButton: {
    marginTop: 12,
    marginHorizontal: 22,
    backgroundColor: '#ECF7EF',
    borderRadius: 20,
    paddingVertical: 15,
    alignItems: 'center'
  },
  secondaryButtonText: {
    color: '#1E7A45',
    fontSize: 16,
    fontWeight: '800'
  },
  textButton: {
    marginTop: 10,
    marginBottom: 22,
    alignItems: 'center',
    paddingVertical: 10
  },
  textButtonText: {
    color: '#2F6E48',
    fontSize: 15,
    fontWeight: '800'
  }
});

export default OrderConfirmedScreen;
